import { isClefHsmArn, pkcs11UriToSyntheticArn, syntheticArnToPkcs11Uri } from "./hsm-arn";

/**
 * Canonical cross-language interop vectors. These are the contractual
 * payloads the keyservice team publishes; they were generated by
 * `Go base64.RawURLEncoding.EncodeToString` and must round-trip
 * byte-identical through `Buffer.from(uri).toString("base64url")`.
 *
 * If either vector ever fails it means a runtime changed encoding
 * behavior and we have an interop break — flag immediately, do not
 * silently regenerate.
 */
const CANONICAL_VECTORS: Array<{ uri: string; payload: string }> = [
  {
    uri: "pkcs11:slot=0;label=clef-dek-wrapper",
    payload: "cGtjczExOnNsb3Q9MDtsYWJlbD1jbGVmLWRlay13cmFwcGVy",
  },
  {
    uri: "pkcs11:slot=0;label=foo;hash=sha1",
    payload: "cGtjczExOnNsb3Q9MDtsYWJlbD1mb287aGFzaD1zaGEx",
  },
  {
    uri: "pkcs11:slot=12345;object=wrap-key",
    payload: "cGtjczExOnNsb3Q9MTIzNDU7b2JqZWN0PXdyYXAta2V5",
  },
];

const ARN_PREFIX = "arn:aws:kms:us-east-1:000000000000:alias/clef-hsm/v1/";

describe("pkcs11UriToSyntheticArn", () => {
  it.each(CANONICAL_VECTORS)("encodes canonical vector for $uri", ({ uri, payload }) => {
    expect(pkcs11UriToSyntheticArn(uri)).toBe(ARN_PREFIX + payload);
  });

  it("rejects input that does not start with pkcs11:", () => {
    expect(() => pkcs11UriToSyntheticArn("file:///key.pem")).toThrow(/Expected a pkcs11 URI/);
  });

  it("rejects empty input", () => {
    expect(() => pkcs11UriToSyntheticArn("")).toThrow(/Expected a pkcs11 URI/);
  });

  it("emits an ARN that passes the contract regex", () => {
    const arn = pkcs11UriToSyntheticArn("pkcs11:slot=0;label=foo");
    expect(isClefHsmArn(arn)).toBe(true);
  });

  it("base64url alphabet contains no + / = characters in the payload", () => {
    // pkcs11 URIs with high-entropy labels can produce payloads that would
    // contain + or / in standard base64; URL-safe encoding must replace them.
    // Slice past the structural ARN prefix (which legitimately contains /)
    // so we only inspect the payload tail.
    const arn = pkcs11UriToSyntheticArn("pkcs11:slot=99;label=??>>some/path+padding");
    const payload = arn.slice(ARN_PREFIX.length);
    expect(payload).not.toMatch(/[+/=]/);
  });
});

describe("syntheticArnToPkcs11Uri", () => {
  it.each(CANONICAL_VECTORS)("decodes canonical vector for $uri", ({ uri, payload }) => {
    expect(syntheticArnToPkcs11Uri(ARN_PREFIX + payload)).toBe(uri);
  });

  it("round-trips arbitrary pkcs11 URIs losslessly", () => {
    const samples = [
      "pkcs11:slot=0;label=a",
      "pkcs11:slot-id=12345;object=wrap-key;hash=sha384",
      "pkcs11:token=My%20Token;label=key-1",
    ];
    for (const uri of samples) {
      expect(syntheticArnToPkcs11Uri(pkcs11UriToSyntheticArn(uri))).toBe(uri);
    }
  });

  it("returns null for non-Clef ARNs", () => {
    expect(
      syntheticArnToPkcs11Uri(
        "arn:aws:kms:us-east-1:111122223333:key/12345678-1234-1234-1234-123456789012",
      ),
    ).toBeNull();
  });

  it("returns null for ARNs in other AWS partitions but with our marker", () => {
    // Partition tolerance comes from the regex — this should decode.
    const payload = "cGtjczExOnNsb3Q9MDtsYWJlbD1mb28";
    const govArn = `arn:aws-us-gov:kms:us-gov-west-1:000000000000:alias/clef-hsm/v1/${payload}`;
    expect(syntheticArnToPkcs11Uri(govArn)).toBe("pkcs11:slot=0;label=foo");
  });

  it("returns null for unsupported version markers", () => {
    const payload = "cGtjczExOnNsb3Q9MDtsYWJlbD1mb28";
    const v2Arn = `${ARN_PREFIX.replace("/v1/", "/v2/")}${payload}`;
    expect(syntheticArnToPkcs11Uri(v2Arn)).toBeNull();
  });

  it("returns null when the regex matches but the decoded payload is not pkcs11", () => {
    // base64url("hello world") = "aGVsbG8gd29ybGQ"
    const arn = ARN_PREFIX + "aGVsbG8gd29ybGQ";
    expect(syntheticArnToPkcs11Uri(arn)).toBeNull();
  });

  it("returns null when ARN structure is wrong (key/ instead of alias/)", () => {
    const arn = "arn:aws:kms:us-east-1:000000000000:key/clef-hsm/v1/cGtjczExOnNsb3Q9MA";
    expect(syntheticArnToPkcs11Uri(arn)).toBeNull();
  });

  it("returns null when ARN is empty", () => {
    expect(syntheticArnToPkcs11Uri("")).toBeNull();
  });
});

describe("isClefHsmArn", () => {
  it("returns true for ARNs that match the contract", () => {
    expect(isClefHsmArn(pkcs11UriToSyntheticArn("pkcs11:slot=0;label=x"))).toBe(true);
  });

  it("returns false for plain AWS KMS ARNs", () => {
    expect(isClefHsmArn("arn:aws:kms:us-east-1:111122223333:alias/my-real-key")).toBe(false);
  });

  it("returns false for substrings that look like Clef ARNs", () => {
    // Defensive: anchored regex must reject prefix/suffix injections.
    expect(
      isClefHsmArn("prefix-arn:aws:kms:us-east-1:000000000000:alias/clef-hsm/v1/cGtjczExOg"),
    ).toBe(false);
    expect(
      isClefHsmArn("arn:aws:kms:us-east-1:000000000000:alias/clef-hsm/v1/cGtjczExOg-suffix!"),
    ).toBe(false);
  });

  it("returns false for empty input", () => {
    expect(isClefHsmArn("")).toBe(false);
  });
});
